import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/linux-java-version.Bae4eMgj.js";const a=JSON.parse(`{"title":"Instalowanie oprogramowania Java na Linux","description":"Przewodnik krok po kroku o tym, jak zainstalować oprogramowanie Java na Linux.","frontmatter":{"title":"Instalowanie oprogramowania Java na Linux","description":"Przewodnik krok po kroku o tym, jak zainstalować oprogramowanie Java na Linux.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pl_pl/1.21.1/players/installing-java/linux.md","filePath":"versions/1.21.1/translated/pl_pl/players/installing-java/linux.md","lastUpdated":1761424914000}`);var o={name:`pl_pl/1.21.1/players/installing-java/linux.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalowanie oprogramowania Java na Linux <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalowanie oprogramowania Java na Linux”">​</a></h1><p>Ten przewodnik pokaże ci, jak zainstalować Javę 21 na systemie Linux.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Sprawdź, czy nie masz już zainstalowanej Javy <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Sprawdź, czy nie masz już zainstalowanej Javy”">​</a></h2><p>Otwórz terminal, wpisz <code>java -version</code> i naciśnij <kbd>Enter</kbd>.</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Terminal z wpisanym poleceniem &quot;java -version&quot;" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Aby używać Minecrafta w wersji 1.21, musisz mieć zainstalowaną co najmniej Javę 21. Jeśli to polecenie wyświetla wersję mniejszą niż 21, wymagane będzie zaktualizowanie istniejącej instalacji Javy.</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. Pobieranie i instalowanie Javy 21 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. Pobieranie i instalowanie Javy 21”">​</a></h2><p>Zalecamy wykorzystanie OpenJDK 21, który jest dostępny dla większości dystrybucji systemu Linux.</p><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Więcej informacji na temat instalowania Javy na systemie Linux Arch, znajdziesz na <a href="https://wiki.archlinux.org/title/Java" target="_blank" rel="noreferrer">Arch Linux Wiki</a>.</p></div><p>Najnowszą wersję środowiska JRE możesz zainstalować z oficjalnych repozytoriów:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Jeśli prowadzisz serwer bez potrzeby korzystania z interfejsu graficznego, możesz zainstalować wersję headless (bez interfejsu graficznego):</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Natomiast jeśli planujesz tworzyć mody, będzie ci potrzebny JDK:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jdk-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="debian-ubuntu" tabindex="-1">Debian/Ubuntu <a class="header-anchor" href="#debian-ubuntu" aria-label="Permalink to “Debian/Ubuntu”">​</a></h3><p>Możesz zainstalować Javę 21 przy użyciu <code>apt</code> następującymi poleceniami:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk-21-jdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="fedora" tabindex="-1">Fedora <a class="header-anchor" href="#fedora" aria-label="Permalink to “Fedora”">​</a></h3><p>Możesz zainstalować Javę 21 przy użyciu <code>dnf</code> następującymi poleceniami:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Jeśli nie potrzebujesz interfejsu graficznego, możesz zainstalować wersję headless (bez interfejsu graficznego):</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Natomiast jeśli planujesz tworzyć mody, będzie ci potrzebny JDK:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk-devel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="other-linux-distributions" tabindex="-1">Inne dystrybucje systemu Linux <a class="header-anchor" href="#other-linux-distributions" aria-label="Permalink to “Inne dystrybucje systemu Linux”">​</a></h3><p>Jeśli twoja dystrybucja nie jest wymieniona powyżej, możesz pobrać najnowszą wersję środowiska JRE ze strony <a href="https://adoptium.net/temurin/" target="_blank" rel="noreferrer">Adoptium</a></p><p>Jeśli planujesz tworzyć mody, zapoznaj się z alternatywnym przewodnikiem dla swojej dystrybucji.</p><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. Zweryfikuj czy Java 21 została zainstalowana <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. Zweryfikuj czy Java 21 została zainstalowana”">​</a></h2><p>Po zakończeniu instalacji możesz zweryfikować czy Java 21 została zainstalowana, otwierając terminal i wpisując <code>java -version</code>.</p><p>Jeśli polecenie zostanie uruchomione pomyślnie, to zobaczysz coś takiego, gdzie wyświetlana jest wersja Javy:</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Terminal z wpisanym poleceniem &quot;java -version&quot;" loading="lazy"></p>`,33)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};